# -*- coding: utf-8 -*-
GLOBAL = [
    {"hero":True,"sub":"Conflicts & Security","h3":"US strikes Iran after tanker hit in Strait of Hormuz","summary":"American forces hit Iranian targets after a commercial vessel was attacked in the Strait of Hormuz, straining a fragile ceasefire.","body":["US forces struck Iranian targets on Friday after Tehran was blamed for attacking a commercial ship in the Strait of Hormuz, a flashpoint that has rattled the truce framework agreed earlier this year. The exchange came as Washington, Tehran, Israel and Lebanon try to hold together a memorandum of understanding meant to formally end the 2026 war.","A UN shipping agency paused vessel evacuations through the strait after the attack. The IAEA chief said a much stronger verification regime is needed inside Iran to ensure the country does not move toward nuclear weapons during the 60-day window for further talks."],"sources":[("Fox News","https://www.foxnews.com/live-news/iran-drone-strait-of-hormuz-israel-lebanon-conflict-june-26-2026"),("Al Jazeera","https://www.aljazeera.com/news/liveblog/2026/6/21/iran-war-live-vance-heads-to-switzerland-israel-kills-16-in-lebanon")]},
    {"sub":"Conflicts & Security","h3":"Israel signals open-ended buffer zone in south Lebanon","summary":"Israel says it will hold its buffer zone in southern Lebanon until the Lebanese army can dismantle Hezbollah.","body":["Israel's ambassador to the US said troops will stay in a buffer zone in southern Lebanon with no fixed withdrawal timetable, tying any pullout to the Lebanese Armed Forces proving they can disarm Hezbollah and take over security. The comments underscore how far the parties remain from a durable arrangement.","The stance complicates the wider ceasefire effort linking the US, Iran, Israel and Lebanon, with each side wary of moving first on the ground."],"sources":[("Times of Israel","https://www.timesofisrael.com/liveblog-june-26-2026/")]},
    {"sub":"Conflicts & Security","h3":"Ukraine hammers Russian targets in Crimea as strikes spread","summary":"Kyiv struck Russian air defenses and a strategic bridge in Crimea while Russia kept up deadly attacks on Ukrainian cities.","body":["Ukraine's security service said Crimea has become a zone of constant Russian losses after strikes on air defenses, military airfields and a strategic bridge. Officials framed the campaign as raising the cost of the war for Moscow and testing Vladimir Putin's resolve.","Russia answered with overnight drone and missile attacks, hitting an apartment block in Izium and industrial sites near Kremenchuk. Kyiv reported more than 250 combat clashes in 24 hours with the heaviest pressure around Pokrovsk, and hinted a prisoner exchange could come soon."],"sources":[("Kyiv Independent","https://kyivindependent.com/ukraine-war-latest-crimea-now-zone-of-constant-losses-sbu-says-after-strikes-on-russian-air-defenses-military-airfields/"),("Al Jazeera","https://www.aljazeera.com/news/2026/6/25/as-ukraine-seizes-first-chance-to-win-war-horrors-come-home-to-russia")]},
    {"sub":"Conflicts & Security","h3":"China and Taiwan coast guards face off near Pratas","summary":"Chinese law enforcement ships pushed into Taiwan-claimed waters in a quiet escalation around remote outposts.","body":["Chinese and Taiwanese coast guard vessels squared off near the Taiwan-controlled Pratas Islands, with a Chinese ship ignoring radio warnings and accelerating into restricted waters. Beijing also sent law enforcement ships into prohibited waters around Taiping Island for the first time.","Analysts see the moves as an effort to normalize a Chinese presence around Taiwan's far-flung outposts, laying groundwork for effective control. The carrier Liaoning returned to Qingdao after a deployment of more than 40 days in the South China Sea and West Pacific."],"sources":[("AEI","https://www.aei.org/articles/china-taiwan-update-june-26-2026/"),("SCMP","https://www.scmp.com/news/china/military/article/3357065/quiet-escalation-unfolding-around-taiwans-remote-outposts-beijing-sends-ships")]},
    {"sub":"Conflicts & Security","h3":"Pro-government forces gain ground on M23 in eastern Congo","summary":"Congolese forces and allied militias pushed against M23 in the Kivus as peace talks prepared to resume.","body":["Pro-Congolese forces reported gains around Minembwe in the South Kivu highlands, while allied Wazalendo fighters said they repelled an M23 attack in Walikale district. A tenth round of talks in Switzerland was expected in the coming weeks.","Human Rights Watch said Rwandan forces and M23 carried out forced recruitment and abusive detention of thousands of fighters and civilians, deepening the humanitarian toll of the conflict."],"sources":[("Critical Threats","https://www.criticalthreats.org/briefs/congo-war-security-review"),("Human Rights Watch","https://www.hrw.org/news/2026/06/10/dr-congo-rwanda-m23-forcibly-recruit-detain-thousands")]},
    {"sub":"Conflicts & Security","h3":"US says it killed Venezuelan gang leader in airstrike","summary":"Washington said it killed a notorious Venezuelan gang chief as a vast US military buildup persists in the Caribbean.","body":["President Trump said US forces, coordinating with Venezuelan authorities, killed Hector Guerrero, known as Nino Guerrero, in a June airstrike. Venezuelan officials confirmed their role in the operation.","The strike followed a months-long buildup under Operation Southern Spear, one of the largest US deployments in the Americas in decades, which earlier culminated in the predawn capture of Nicolas Maduro and his transfer to US custody."],"sources":[("Wikipedia","https://en.wikipedia.org/wiki/2026_United_States_intervention_in_Venezuela"),("CFR","https://www.cfr.org/articles/operation-southern-spear-us-military-campaign-targeting-venezuela")]},
    {"sub":"Diplomacy & Trade","h3":"Rutte meets Trump in Washington ahead of Ankara summit","summary":"NATO chief Mark Rutte met Trump to prepare for the July alliance summit, with defense spending topping the agenda.","body":["NATO Secretary General Mark Rutte met President Trump in Washington on Wednesday to set up the July 7-8 summit in Ankara, telling reporters that Europe is stepping up. Many European members now meet or exceed the 2 percent of GDP target, with some planning toward Trump's 5 percent ambition.","The summit aims to project unity after a year of transatlantic friction over Greenland, the Iran war and US force posture in Europe, even as the Pentagon shifts planning toward a possible conflict with China."],"sources":[("GlobalSecurity","https://www.globalsecurity.org/military/library/news/2026/06/mil-260625-nato01.htm"),("Washington Times","https://www.washingtontimes.com/news/2026/jun/25/bigger-defense-spending-top-agenda-upcoming-nato-summit-turkey/")]},
    {"sub":"Diplomacy & Trade","h3":"ICC judges sue Trump over sanctions they call unlawful","summary":"Three International Criminal Court judges sued the Trump administration, saying sanctions amount to an attack on judicial independence.","body":["Judges Kimberly Prost, Solomy Balungi Bossa and Reine Adelaide Sophie Alapini-Gansou filed suit in Manhattan federal court, arguing US sanctions were designed to punish and coerce them. The measures blocked their US assets and cut them off from banking, travel and common online services.","The sanctions followed the court's arrest warrant for Israeli Prime Minister Benjamin Netanyahu and a past case into alleged US war crimes in Afghanistan. The judges say the measures exceeded the law and were not based on a genuine national emergency."],"sources":[("Al Jazeera","https://www.aljazeera.com/news/2026/6/25/icc-judges-sue-trump-over-sanctions-call-measures-unlawful"),("Open Society Justice Initiative","https://www.justiceinitiative.org/newsroom/icc-judges-sue-trump-administration-over-icc-sanctions")]},
    {"sub":"Diplomacy & Trade","h3":"USTR moves toward 25% tariff on Brazilian goods","summary":"Washington proposed a new 25 percent tariff on most Brazilian imports as trade tensions with Brasilia harden.","body":["The US Trade Representative proposed a 25 percent tariff on most goods from Brazil, with limited exceptions, a step that solidifies pressure after earlier IEEPA tariffs were rescinded in February. Brazilian Senator Flavio Bolsonaro registered to testify against the plan at a trade commission hearing.","Separately, US Customs published proposed rules to indefinitely suspend the de minimis exemption for low-value imports, and the USTR floated new tariffs on 60 countries under forced-labor investigations."],"sources":[("Wilson Sonsini","https://www.wsgr.com/en/insights/key-us-import-developments-june-2026.html"),("Tax Foundation","https://taxfoundation.org/research/all/federal/trump-tariffs-trade-war/")]},
    {"sub":"Diplomacy & Trade","h3":"US eases some Section 232 metals tariffs to 15%","summary":"Washington trimmed steel, aluminum and copper tariffs for select products and trade-deal partners.","body":["The US adjusted Section 232 tariffs on certain steel, aluminum and copper goods, cutting the rate to 15 percent from 25 percent for some agricultural, industrial and HVAC equipment. Extra relief went to partners that recently signed trade deals, including the UK, EU, Switzerland, Taiwan, Japan and South Korea.","The carve-outs reward countries that have aligned with US trade terms while keeping leverage over others still negotiating."],"sources":[("Wilson Sonsini","https://www.wsgr.com/en/insights/key-us-import-developments-june-2026.html")]},
    {"sub":"Diplomacy & Trade","h3":"Canada to send warships to Indo-Pacific in twin deployments","summary":"Ottawa plans two naval deployments to the Indo-Pacific to deepen ties with allies while courting trade with China.","body":["Canada said it will dispatch warships to the Indo-Pacific in two deployments this year, part of a push to strengthen military links with regional partners. The plan sits alongside efforts to build closer trade relations with Beijing.","The dual-track approach reflects the balancing act facing middle powers as US strategic focus tilts toward Asia."],"sources":[("CNBC","https://www.cnbc.com/world-politics/")]},
    {"sub":"Diplomacy & Trade","h3":"Bessent says US gas prices set to fall after Iran war","summary":"The Treasury secretary said energy markets are stabilizing and pump prices should drop following the Iran conflict.","body":["Treasury Secretary Scott Bessent said gasoline prices are expected to ease as energy markets settle after the war with Iran, arguing the US economy stayed resilient through the fighting. The remarks aimed to reassure consumers amid lingering volatility around the Strait of Hormuz.","Oil markets remain sensitive to any renewed disruption in the strait, a chokepoint for a large share of global crude shipments."],"sources":[("Fox News","https://www.foxnews.com/live-news/iran-drone-strait-of-hormuz-israel-lebanon-conflict-june-26-2026")]},
    {"sub":"Humanitarian & Climate","h3":"Famine confirmed in Sudan's Al Fasher and Kadugli","summary":"UN agencies confirmed famine in two Sudanese towns as nearly 20 million people face crisis-level hunger.","body":["UNICEF and partners confirmed famine conditions in Al Fasher in North Darfur and Kadugli in South Kordofan, towns largely cut off from aid by fighting. More than 19.5 million Sudanese, roughly two in five, face crisis levels of food insecurity, with 825,000 children expected to suffer severe acute malnutrition this year.","Agencies urged an immediate halt to hostilities and more funding before the June-to-September lean season worsens shortages. Some 9 million people have been displaced by the conflict."],"sources":[("UNICEF","https://www.unicef.org/press-releases/famine-conditions-confirmed-sudans-al-fasher-and-kadugli"),("WFP","https://www.wfp.org/emergencies/sudan")]},
    {"sub":"Humanitarian & Climate","h3":"Europe's deadly heatwave breaks records across the continent","summary":"A severe heatwave killed dozens and shattered temperature records from France to the UK.","body":["France logged its hottest day since records began in 1947, while the UK recorded its hottest June day at a provisional 35.7C. The second and more intense heatwave began just before the summer solstice, hitting Belgium, Germany, Italy, Spain and the Netherlands.","French Prime Minister Sebastien Lecornu linked dozens of drownings to people seeking relief from the heat, and Enedis reported 50,000 customers without power. Forecasters warned of wildfire risk and severe thunderstorms as the system breaks down."],"sources":[("Al Jazeera","https://www.aljazeera.com/news/2026/6/24/deaths-disruptions-across-europe-what-you-should-know-about-the-heatwave"),("WMO","https://wmo.int/media/news/records-fall-extreme-heat-grips-europe")]},
    {"sub":"Humanitarian & Climate","h3":"Aid still throttled in Gaza despite ceasefire","summary":"Gaza remains in famine conditions even after a ceasefire, with restrictions still choking aid deliveries.","body":["The Gaza Strip was the worst-affected place in the latest global hunger data, with about 640,700 people facing famine, around 32 percent of its population and the highest share recorded anywhere. It marked the first time famine had been officially confirmed in the Middle East.","Although aid flows rose after a ceasefire took effect on 10 October, agencies say continued restrictions keep the situation critical, with young children most at risk."],"sources":[("World Peace Foundation","https://worldpeacefoundation.org/blog/famine-in-sudan-famine-in-gaza-visualizing-the-data/"),("Al Jazeera","https://www.aljazeera.com/news/2026/4/24/global-hunger-report-warns-of-rising-malnutrition-and-famine-risks")]},
    {"sub":"Humanitarian & Climate","h3":"IAEA chief presses for tougher inspections inside Iran","summary":"The UN nuclear watchdog says a very strong verification system is needed to keep Iran from weapons work.","body":["The head of the IAEA said a very strong verification regime must be put in place in Iran after the Middle East conflict to guard against any move toward nuclear weapons. The call comes during a fragile 60-day window meant to resolve outstanding issues including Iran's program.","Inspectors face the challenge of rebuilding access and confidence after months of war disrupted monitoring."],"sources":[("Times of Israel","https://www.timesofisrael.com/liveblog-june-26-2026/")]},
    {"sub":"Humanitarian & Climate","h3":"Benelux storms bring tornado-like damage amid heat","summary":"A severe thunderstorm tore through the Benelux region, with the Netherlands logging record lightning and suspected tornado damage.","body":["A violent thunderstorm swept the entire Benelux area, with the Netherlands recording more than 188,000 lightning strikes in one night and significant damage in eastern Groningen suspected to be from an EF-2 tornado. The storms punctuated weeks of extreme heat across the region.","Forecasters warned of more severe weather as the heatwave broke, with hail, damaging gusts and heavy rain capable of localized destruction."],"sources":[("Earth.Org","https://earth.org/this-week-in-climate-news-june-2026-week-1/")]}
]

NETHERLANDS = [
    {"hero":True,"sub":"Politics & Policy","h3":"Dutch ministers lobby Washington to spare ASML","summary":"Cabinet members flew to Washington to fight US plans that would sharply curb ASML's China sales.","body":["Dutch ministers held talks in Washington over the proposed MATCH Act, which would bar ASML from shipping lower-end deep ultraviolet machines to China and from servicing existing Chinese customers. Trade Minister Sjoerd Sjoerdsma met Commerce Secretary Howard Lutnick and lawmakers to press the case.","The Dutch government is irritated that the bill would let the US decide what partner countries can export. ASML earned about 27 billion euros in China over three years, between 26 and 36 percent of its revenue, leaving the firm heavily exposed."],"sources":[("NL Times","https://nltimes.nl/2026/06/24/dutch-government-irritated-us-plans-new-asml-export-restrictions"),("Bloomberg","https://www.bloomberg.com/news/articles/2026-06-24/netherlands-lobbies-us-to-drop-chip-curbs-targeting-asml-sales"),("DutchNews","https://www.dutchnews.nl/2026/06/netherlands-joins-us-chip-pact-while-fighting-asml-export-curbs/")]},
    {"sub":"Politics & Policy","h3":"Cabinet readies tougher nitrogen cuts before recess","summary":"Agriculture Minister Jaimi van Essen is set to present a new nitrogen package as farmer protest fears return.","body":["The cabinet prepared to unveil a nitrogen plan before the summer recess that would require farmers, industry and transport to cut emissions within nine years against 2019 levels. Farmers would face reductions of 42 to 46 percent, with industry and mobility facing 50 percent cuts.","Officials braced for renewed protests, noting rural anger is already high. A tractor has appeared at asylum-related demonstrations, reflecting how the nitrogen fight has fused with migration grievances on the right."],"sources":[("NL Times","https://nltimes.nl/2026/05/18/dutch-cabinet-prepares-tougher-nitrogen-cuts-farmer-protest-fears-return"),("DutchReview","https://dutchreview.com/culture/dutch-nitrogen-crisis-explained/")]},
    {"sub":"Politics & Policy","h3":"Jetten minority cabinet steers Dutch policy four months in","summary":"The D66-led Jetten cabinet, sworn in February, sets the agenda on housing and chips heading into summer.","body":["The minority cabinet of D66, VVD and CDA, presented in late January and sworn in on 23 February, replaced the short-lived Schoof government. The October 2025 election left D66 and the PVV tied at 26 seats each, an unprecedented deadlock.","Now four months in, the government is balancing affordable housing pledges with the ASML export fight and a fresh nitrogen package that risks reigniting farmer unrest."],"sources":[("Wikipedia","https://en.wikipedia.org/wiki/2025%E2%80%932026_Dutch_cabinet_formation"),("Atlantic Council","https://www.atlanticcouncil.org/content-series/eye-on-europes-elections/your-primer-on-the-dutch-general-elections/")]},
    {"sub":"Politics & Policy","h3":"Dutch back US chip pact even as they fight ASML curbs","summary":"The Netherlands joined a US-led chip alignment effort while resisting the harshest export limits on ASML.","body":["The Netherlands signed onto a US chip cooperation pact while simultaneously pushing back on the MATCH Act's reach over ASML's China business. The dual stance reflects an attempt to stay aligned with Washington without crippling a flagship company.","The bill has cleared a committee but not the full Congress, leaving room for Dutch diplomacy to soften its terms before any final vote."],"sources":[("DutchNews","https://www.dutchnews.nl/2026/06/netherlands-joins-us-chip-pact-while-fighting-asml-export-curbs/"),("SCMP","https://www.scmp.com/news/china/diplomacy/article/3353452/netherlands-protests-us-proposal-further-bar-chip-giant-asml-china-market")]},
    {"sub":"Economy & Housing","h3":"Dutch house prices keep climbing as growth cools","summary":"Average home prices near 486,000 euros, up 4 to 5 percent on the year, even as the market loses steam.","body":["The average Dutch home cost about 486,000 euros in 2026, roughly 4 to 5 percent higher than a year earlier. DNB's spring projections expect annual price gains of 3 to 4 percent through 2028 as confidence dips and mortgage rates rise.","A persistent shortage of homes, especially in the Randstad, keeps prices high for first-time buyers and lower-income households. The Jetten government has pledged more construction and affordable rentals."],"sources":[("DNB","https://www.dnb.nl/en/current-economic-issues/housing-market/"),("Global Property Guide","https://www.globalpropertyguide.com/europe/netherlands/price-history")]},
    {"sub":"Economy & Housing","h3":"IMF sees Dutch growth easing to 1.2% in 2026","summary":"The Dutch economy is set to slow after a resilient 2025, with the IMF projecting 1.2 percent growth this year.","body":["After real GDP grew 1.9 percent in 2025 by IMF figures, the fund projects 1.2 percent growth in 2026 and 1.4 percent in 2027. Fitch reaffirmed the Netherlands' AAA rating with a stable outlook early in the year.","Outstanding housing loans reached 890.2 billion euros at the end of 2025, with the loan stock growing 4.6 percent, underscoring how central mortgage debt remains to the economy."],"sources":[("Global Property Guide","https://www.globalpropertyguide.com/europe/netherlands/price-history"),("DNB","https://www.dnb.nl/en/current-economic-issues/housing-market/")]},
    {"sub":"Economy & Housing","h3":"Heat forces emergency measures on Dutch rail","summary":"Extreme heat and engineering works disrupted Dutch trains, with reduced service around Amsterdam and Schiphol.","body":["Rail operators across the Netherlands cut and adjusted services as an unprecedented heatwave combined with ProRail engineering works. Trains to and from Amsterdam Zuid were halted, with fewer services to Amsterdam RAI and between Amsterdam Central and Schiphol.","The disruption hit cross-border capacity too, as operators in Belgium, France and the UK took similar steps to protect passengers and infrastructure from thermal stress."],"sources":[("Travel And Tour World","https://www.travelandtourworld.com/news/article/gdgsi78clp4h/"),("NS","https://www.ns.nl/en/travel-information/better-journey/werkzaamheden-amsterdam.html")]},
    {"sub":"Economy & Housing","h3":"New off-peak summer rail pass launches at 49 euros","summary":"NS rolled out a cut-price off-peak season ticket to encourage cheaper summer train travel.","body":["From 15 June the Netherlands introduced the Nederland Dal Vrij Trein pass, an adapted version of the NS Flex Dal Vrij product, priced at 49 euros a month for off-peak travel. The aim is to make summer rail trips more affordable.","The launch lands awkwardly against heat-driven service cuts, testing whether cheaper fares can coexist with a strained network."],"sources":[("Railway Pro","https://www.railwaypro.com/wp/the-netherlands-launches-a-special-ticket-for-affordable-rail-travel/"),("Railway Supply","https://www.railway.supply/nederland-dal-vrij-trein-starts-on-june-15-2026-in-netherlands/")]},
    {"sub":"Society & Culture","h3":"Netherlands issues first-ever code red heat warning","summary":"KNMI declared its first historic code red for heat as temperatures pushed toward 40C.","body":["The KNMI issued the country's first code red heat warning, with forecasts of 36C to 39C and isolated spots near 40C. Many schools closed and authorities urged people to stay off the roads as the warnings ran through at least Sunday.","The Netherlands also recorded its warmest June night on record, with wildfire risk rising and a code yellow for severe thunderstorms set to spread nationwide on Saturday evening."],"sources":[("NL Times","https://nltimes.nl/2026/06/26/code-red-heat-alarm-temps-40degc-many-schools-closed-stay-roads"),("DutchNews","https://www.dutchnews.nl/2026/06/warmest-june-night-ever-as-events-cancelled-wildfire-risk/")]},
    {"sub":"Society & Culture","h3":"Defqon.1 cancelled as heat shuts festival gates","summary":"The Defqon.1 festival was fully cancelled after the historic code red heat warning.","body":["Organizers cancelled the Defqon.1 festival in Biddinghuizen, closing the gates from Friday as the code red took effect. About 58,000 campers and 15,000 day-ticket holders per day had been expected.","Promoters first tried extra shade, hydration and scrapped day tickets to thin the crowd, but the extreme heat proved too dangerous. All ticket holders will be refunded and the campground stays open for safe departure."],"sources":[("NL Times","https://nltimes.nl/2026/06/26/defqon1-festival-canceled-netherlands-issues-code-red-alarm-extreme-heat"),("DJ Mag","https://djmag.com/news/defqon1-festival-cancelled-due-extreme-heat-warning")]},
    {"sub":"Society & Culture","h3":"Heat drives wildfire risk and event cancellations","summary":"Authorities warned of rising wildfire danger and pulled events as the country baked in tropical heat.","body":["With the warmest June night on record behind it, the Netherlands faced elevated wildfire risk and a wave of cancelled outdoor events. Officials advised people to limit exertion and stay hydrated during the peak days.","Forecasters cautioned that the breakdown of the heat could be violent, with severe thunderstorms, hail and heavy rain threatening localized damage into the weekend."],"sources":[("DutchNews","https://www.dutchnews.nl/2026/06/warmest-june-night-ever-as-events-cancelled-wildfire-risk/"),("IamExpat","https://www.iamexpat.nl/lifestyle/lifestyle-news/ropical-heat-continues-netherlands-highs-38c-week")]},
    {"sub":"Society & Culture","h3":"Dutch farmer anger fuses with asylum protests","summary":"Tractors are appearing at asylum demonstrations as nitrogen and migration grievances merge on the right.","body":["A tractor was spotted at asylum-related protests in Loosdrecht, illustrating how rural anger over nitrogen rules is blending with anti-migration sentiment. Conspiracy-driven online groups and some lawmakers baselessly claim farms are being closed to house asylum-seekers.","The convergence has powered the BBB and strengthened Geert Wilders' PVV, turning a regulatory dispute into an ideological battle ahead of a tense protest summer."],"sources":[("DutchReview","https://dutchreview.com/culture/dutch-nitrogen-crisis-explained/"),("NL Times","https://nltimes.nl/2026/05/18/dutch-cabinet-prepares-tougher-nitrogen-cuts-farmer-protest-fears-return")]}
]

MOOD = {"h3":"Sfeer vandaag","p":"Het land kreunt onder een historische hittegolf, met code rood en temperaturen rond 33 tot 36 graden in heel Nederland. Scholen blijven dicht, festivals zoals Defqon.1 zijn afgelast en het advies is om binnen te blijven en de weg te mijden. Vanavond dreigt de hitte abrupt te breken met zware onweersbuien, hagel en kans op wateroverlast."}
